const items = $input.all();
const results = [];

for (const item of items) {
    // days_remaining은 PostgreSQL interval 타입 → 숫자로 변환
    let daysRaw = item.json.days_remaining;
    let daysNum = 0;

    if (typeof daysRaw === 'number') {
        daysNum = daysRaw;
    } else if (typeof daysRaw === 'string') {
        // "90 days", "7 days" 등의 형식 처리
        const match = String(daysRaw).match(/(\d+)/);
        daysNum = match ? parseInt(match[1]) : 0;
    } else if (daysRaw && typeof daysRaw === 'object') {
        // PostgreSQL interval object
        daysNum = parseInt(daysRaw.days || 0);
    }

    let alertStage = '';
    let urgencyLevel = '';
    let priority = 0;

    if (daysNum >= 85 && daysNum <= 90) {
        alertStage = 'D-90';
        urgencyLevel = '정보';
        priority = 1;
    } else if (daysNum >= 55 && daysNum <= 65) {
        alertStage = 'D-60';
        urgencyLevel = '주의';
        priority = 2;
    } else if (daysNum >= 40 && daysNum <= 50) {
        alertStage = 'D-45';
        urgencyLevel = '중요';
        priority = 3;
    } else if (daysNum >= 25 && daysNum <= 35) {
        alertStage = 'D-30';
        urgencyLevel = '긴급';
        priority = 4;
    } else if (daysNum >= 10 && daysNum <= 16) {
        alertStage = 'D-14';
        urgencyLevel = '매우긴급';
        priority = 5;
    } else if (daysNum >= 5 && daysNum <= 9) {
        alertStage = 'D-7';
        urgencyLevel = '최종경고';
        priority = 6;
    } else if (daysNum >= 0 && daysNum <= 4) {
        alertStage = 'D-0';
        urgencyLevel = '위기';
        priority = 7;
    }

    // 알림 단계가 없으면 건너뜀 (중간 날짜는 알림 불필요)
    if (!alertStage) continue;

    const endDate = new Date(item.json.end_date);
    const formattedEnd = endDate.toLocaleDateString('ko-KR', {year:'numeric',month:'long',day:'numeric'});

    results.push({
        json: {
            ...item.json,
            days_remaining: daysNum,
            alert_stage: alertStage,
            urgency_level: urgencyLevel,
            priority: priority,
            notification_date: new Date().toISOString(),
            formatted_end_date: formattedEnd,
            formatted_amount: parseInt(item.json.monthly_amount || 0).toLocaleString('ko-KR'),
            // 이메일 폴백: email 없으면 CC 담당자에게 알림
            effective_email: item.json.sales_rep_email || 'htkim@dsti.co.kr'
        }
    });
}

return results;

